
import { Options, Vue } from "vue-class-component";
import CTheme from "@/components/Theme.vue";

@Options({
  components: {CTheme}
})
export default class Header extends Vue {
  scrolled = 0;
  top = 0;

  show = false;
  dark = false;
  openMenu = false;

  mounted() {
    window.addEventListener("scroll", () => {
      this.show = window.scrollY < this.scrolled || window.scrollY <= 0;
      this.top = this.scrolled = window.scrollY;
      this.dark = window.scrollY > 0;

      if (this.show) {
        this.top = 0;
      } else if (this.top > 50) {
        this.top = 50;
      }
    });
  }
}
