import { App } from "vue";

import "boxicons/css/boxicons.min.css";
import "./index.scss";

const colors = {
  $primary: "60, 177, 255",
  $primary2: "74, 85, 104",
  $secondary: "240, 248, 255",
  $danger: "230, 60, 60",
  $light: "255, 255, 255",
  $dark: "32, 32, 32",
  $success: "23, 201, 100",
};

export const init = async (app: App<Element>) => {
  document.documentElement.style.setProperty("--primary", "255, 115, 0");
  document.documentElement.style.setProperty("--danger", "230, 60, 60");
  document.documentElement.style.setProperty("--success", "23, 201, 100");

  document.documentElement.style.setProperty("--white", "255, 255, 255");
  document.documentElement.style.setProperty("--black", "32, 32, 32");
  document.documentElement.style.setProperty("--blue", "60, 177, 255");

  document.documentElement.style.setProperty("--light", "255, 255, 255");
  document.documentElement.style.setProperty("--dark", "32, 32, 32");
  document.documentElement.style.setProperty("--secondary", "240, 248, 255");

  document.documentElement.style.setProperty("--body-color", "rgba(var(--secondary), 1)");
  document.documentElement.style.setProperty("--bd-color", "rgba(var(--dark), 0.1)")

  app.config.globalProperties.$theme = {
    colors
  }

}
