<template>
  <button @click="darkOrLightMode" class="theme" :class="{ dark: theme.dark }">
    <i class="bx bxs-sun"></i>
    <i class="bx bxs-moon" style="margin-left: auto"></i>
    <div class="obj"></div>
  </button>
</template>

<script lang="ts">
import { ITheme } from "@/store/types";
import { Options, Vue } from "vue-class-component";
import { Action, Getter } from "vuex-class";

@Options({})
export default class Theme extends Vue {
  @Getter("get", { namespace: "theme" })
  theme!: ITheme;

  @Action("setDark", { namespace: "theme" })
  setDark!: (value: boolean) => any;

  mounted() {
    this.init();
  }

  init() {
    this.theme.dark ? this.darker() : this.lighter();
  }

  darkOrLightMode() {
    this.theme.dark ? this.lighter() : this.darker();
  }

  darker() {
    document.documentElement.style.setProperty("--light", "32, 32, 32");
    document.documentElement.style.setProperty("--dark", "255, 255, 255");
    document.documentElement.style.setProperty("--secondary", "82, 82, 82");

    this.setDark(true);
  }
  lighter() {
    document.documentElement.style.setProperty("--light", "255, 255, 255");
    document.documentElement.style.setProperty("--dark", "32, 32, 32");
    document.documentElement.style.setProperty("--secondary", "240, 248, 255");

    this.setDark(false);
  }
}
</script>

<style lang="scss" scoped>
.theme {
  height: 22px;
  width: 42px;
  border-radius: 15em;
  background-color: rgba(var(--dark), 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  border: 0;

  padding-left: 5px;
  padding-right: 5px;
  position: relative;
  cursor: pointer;
  box-shadow: rgba(50, 50, 93, 0.25) 0px 30px 60px -12px inset,
    rgba(0, 0, 0, 0.3) 0px 18px 36px -18px inset;

    i::before {
      font-size: 12px;
    }

  .obj {
    position: absolute;
    top: 50%;
    left: -3px;
    background-color: rgba(var(--light), 1);
    width: 25px;
    height: 25px;
    border-radius: 100%;
    transform: translateY(-50%);
    transition: all 0.5s ease;
    box-shadow: rgba(100, 100, 111, 0.2) 0px 7px 29px 0px;
    border: 1px solid #000;
  }

  &.dark {
    i::before {
      color: rgba(var(--dark), 1);
    }
    .obj {
      left: calc(100% - 25px);
    }
  }
}
</style>

