import { Module, ActionTree, MutationTree, GetterTree } from "vuex";
import { RootState, ITheme, ThemeState } from "../types";

const namespaced = true;

const state: ThemeState = {
    theme: { dark: false }
};

const getters: GetterTree<ThemeState, RootState> = {
    get(state): ITheme {
        const { theme } = state;
        return theme;
    }
};

const mutations: MutationTree<ThemeState> = {
    SET_DARK(state, payload: boolean) {
        state.theme.dark = payload;
    }
};

const actions: ActionTree<ThemeState, RootState> = {
    setDark({ commit }, value): any {
        commit("SET_DARK", value);
    }
};

const users: Module<ThemeState, RootState> = {
    namespaced,
    state,
    getters,
    actions,
    mutations
};

export default users;